INSERT INTO articles (id, slug, title, raw_text, difficulty, category, content_json, summary, read_time_minutes, keywords, is_seed_content, is_verified, is_safety_critical) VALUES
(gen_random_uuid(), 'motorcycle-battery-types', 'Motorcycle Battery Types and Maintenance', 'Motorcycle batteries provide starting power, support electrical systems during low-charge conditions, and stabilize voltage supplied by the charging system. Understanding battery types helps riders choose appropriate replacements and troubleshoot electrical problems. Conventional lead-acid batteries use lead plates immersed in sulfuric acid, requiring regular maintenance including periodic water additions to replace lost electrolyte. These batteries are inexpensive and reliable but heavy, requiring careful secure mounting. Absorbed Glass Mat (AGM) batteries use fiberglass mats to absorb electrolyte, eliminating the need for water addition and providing superior vibration resistance. AGM batteries are lighter, more expensive, and less forgiving of overcharging—the charging system must be properly regulated or the battery will be damaged. Lithium-ion batteries represent modern technology, offering extreme weight savings and excellent cold-start performance but requiring careful charging and temperature management. Lithium batteries are extremely expensive and sensitive to overcharging and deep discharge. Most street motorcycles use conventional or AGM batteries. Battery voltage on all motorcycles is 12V, though some large bikes use 24V systems. Battery capacity is rated in amp-hours (Ah)—a 14Ah battery provides 14 amps for one hour. Cold cranking amps (CCA) measures starting power in freezing conditions. Motorcycles typically require 100-200 CCA for reliable starting. Regular charging maintenance is essential—batteries self-discharge when not in use and require periodic charging during extended storage. A dead battery significantly damages internal chemistry through sulfation, reducing lifespan permanently.', 'beginner', 'electrical', '{"sections":[{"heading":"Lead-Acid Batteries","body":"Motorcycle batteries provide starting power, support electrical systems during low-charge conditions, and stabilize voltage supplied by the charging system. Conventional lead-acid batteries use lead plates immersed in sulfuric acid, requiring regular maintenance including periodic water additions to replace lost electrolyte. These batteries are inexpensive and reliable but heavy, requiring careful secure mounting."},{"heading":"AGM and Advanced Batteries","body":"Absorbed Glass Mat (AGM) batteries use fiberglass mats to absorb electrolyte, eliminating the need for water addition and providing superior vibration resistance. AGM batteries are lighter, more expensive, and less forgiving of overcharging—the charging system must be properly regulated or the battery will be damaged. Lithium-ion batteries represent modern technology, offering extreme weight savings and excellent cold-start performance."},{"heading":"Battery Specifications","body":"Battery voltage on all motorcycles is 12V, though some large bikes use 24V systems. Battery capacity is rated in amp-hours (Ah)—a 14Ah battery provides 14 amps for one hour. Cold cranking amps (CCA) measures starting power in freezing conditions. Motorcycles typically require 100-200 CCA for reliable starting."},{"heading":"Maintenance Requirements","body":"Regular charging maintenance is essential—batteries self-discharge when not in use and require periodic charging during extended storage. A dead battery significantly damages internal chemistry through sulfation, reducing lifespan permanently. Always keep batteries properly charged during storage or use a trickle charger."}],"keyTakeaways":["Lead-acid batteries are cheap but require water maintenance","AGM batteries are lighter but less forgiving of overcharging","Battery capacity is measured in amp-hours (Ah)","Dead batteries suffer sulfation damage and shortened lifespan"],"relatedTopics":["electrical","charging-systems","battery-safety","electrical-troubleshooting"]}', 'Learn about motorcycle battery types, capacities, and maintenance practices to ensure reliable starting and electrical performance.', 8, ARRAY['electrical','battery','lead-acid','AGM','lithium','electrical-basics','charging'], true, true, true),

(gen_random_uuid(), 'charging-systems-explained', 'Charging Systems: Alternators and Regulators', 'The charging system replenishes battery charge consumed during starting and powers electrical systems while the engine runs. A charging system consists of three components: the alternator (generator), the voltage regulator, and the battery. The alternator, belt or gear-driven by the engine crankshaft, generates alternating current (AC) voltage proportional to engine RPM. At idle, the alternator produces low voltage; at higher RPMs it produces higher voltage. A voltage regulator converts the alternator''s AC output to DC (direct current) suitable for the battery and electrical systems, and crucially, it limits output voltage to protect electrical components from overcharging. Motorcycle voltage regulators maintain output between 13.8 and 14.4 volts—the optimal range for battery charging and electrical system operation. If the regulator fails high (always allowing full alternator output), the battery will be chronically overcharged, damaging the battery and burning out electrical components. If the regulator fails low (limiting voltage excessively), the alternator won''t adequately charge the battery, leading to a gradually dead battery that eventually prevents starting. A properly functioning charging system produces 13.5-14.5V at 2,000+ engine RPM with the battery connected. At idle, output may drop below battery voltage, but this is normal—the alternator doesn''t produce sufficient current at idle to charge effectively. Testing the charging system requires a multimeter and knowledge of proper test procedures. Many electrical problems stem from charging system failure, making diagnosis important before replacing expensive components.', 'intermediate', 'electrical', '{"sections":[{"heading":"Charging System Components","body":"The charging system replenishes battery charge consumed during starting and powers electrical systems while the engine runs. A charging system consists of three components: the alternator (generator), the voltage regulator, and the battery. The alternator, belt or gear-driven by the engine crankshaft, generates alternating current (AC) voltage proportional to engine RPM."},{"heading":"Voltage Regulation","body":"A voltage regulator converts the alternator''''s AC output to DC (direct current) suitable for the battery and electrical systems, and crucially, it limits output voltage to protect electrical components from overcharging. Motorcycle voltage regulators maintain output between 13.8 and 14.4 volts—the optimal range for battery charging and electrical system operation."},{"heading":"Regulator Failure Modes","body":"If the regulator fails high (always allowing full alternator output), the battery will be chronically overcharged, damaging the battery and burning out electrical components. If the regulator fails low (limiting voltage excessively), the alternator won''''t adequately charge the battery, leading to a gradually dead battery that eventually prevents starting."},{"heading":"Testing and Diagnosis","body":"A properly functioning charging system produces 13.5-14.5V at 2,000+ engine RPM with the battery connected. At idle, output may drop below battery voltage, but this is normal—the alternator doesn''''t produce sufficient current at idle to charge effectively. Testing the charging system requires a multimeter and knowledge of proper test procedures."}],"keyTakeaways":["Alternators generate voltage proportional to engine RPM","Voltage regulators convert AC to DC and limit output to 13.8-14.4V","Regulator failure causes overcharging or undercharging","Proper output is 13.5-14.5V at 2,000+ RPM"],"relatedTopics":["electrical","motorcycle-battery-types","electrical-troubleshooting","starter-motors"]}', 'Understand how charging systems work and how voltage regulation prevents battery overcharge and electrical damage.', 9, ARRAY['electrical','electrical-basics','alternator','regulator','charging','voltage','generator'], true, true, true),

(gen_random_uuid(), 'starter-motor-fundamentals', 'Starter Motors and Starting Systems', 'Starter motors are electric motors that crank the engine until combustion begins and the engine can run under its own power. A starter motor draws massive current from the battery—often 200+ amps—requiring a robust battery connection and proper electrical design. The starter motor contains carbon brushes that transfer electrical current to rotating commutators, allowing the motor to spin. Over time, brushes wear, reducing starter efficiency and requiring replacement. When the rider engages the starter (pushes the starter button), a solenoid (electromagnetic switch) closes, completing the circuit and allowing battery current to flow to the starter motor. The solenoid also mechanically engages a pinion gear on the starter motor shaft with the engine''s ring gear, allowing the starter to crank the crankshaft. When the engine starts and RPM exceeds starter speed, a one-way clutch inside the starter automatically disengages the pinion gear, preventing the engine from "back-driving" the starter motor at extremely high speeds (which would destroy it). Starter problems manifest as slow cranking, clicking sounds without cranking, or complete failure to start. Slow cranking indicates weak battery, corroded connections, or starter motor brush wear. Clicking without cranking typically indicates insufficient battery current—either a dead battery or poor connection. Starter failure requires replacement, though some mechanics rebuild starters by replacing worn brushes and bearings. Modern motorcycles use electric starters exclusively, making starter reliability essential for practical use.', 'intermediate', 'electrical', '{"sections":[{"heading":"Starter Motor Function","body":"Starter motors are electric motors that crank the engine until combustion begins and the engine can run under its own power. A starter motor draws massive current from the battery—often 200+ amps—requiring a robust battery connection and proper electrical design. The starter motor contains carbon brushes that transfer electrical current to rotating commutators, allowing the motor to spin."},{"heading":"Solenoid and Engagement Mechanism","body":"When the rider engages the starter (pushes the starter button), a solenoid (electromagnetic switch) closes, completing the circuit and allowing battery current to flow to the starter motor. The solenoid also mechanically engages a pinion gear on the starter motor shaft with the engine''''s ring gear, allowing the starter to crank the crankshaft."},{"heading":"Safety Disengagement","body":"When the engine starts and RPM exceeds starter speed, a one-way clutch inside the starter automatically disengages the pinion gear, preventing the engine from ''''back-driving'''' the starter motor at extremely high speeds (which would destroy it). This safety mechanism is essential for starter longevity."},{"heading":"Problem Diagnosis","body":"Starter problems manifest as slow cranking, clicking sounds without cranking, or complete failure to start. Slow cranking indicates weak battery, corroded connections, or starter motor brush wear. Clicking without cranking typically indicates insufficient battery current—either a dead battery or poor connection."}],"keyTakeaways":["Starter motors draw 200+ amps during starting","Solenoid engages pinion gear with engine ring gear","One-way clutch automatically disengages starter when engine runs","Slow cranking suggests battery, connections, or brush wear"],"relatedTopics":["electrical","motorcycle-battery-types","charging-systems-explained","electrical-troubleshooting"]}', 'Learn how starter motors work and how to diagnose starting problems related to the starter system.', 9, ARRAY['electrical','electrical-basics','starter-motor','starting','solenoid','battery-drain','engine-starting'], true, true, false),

(gen_random_uuid(), 'ignition-systems-explained', 'Ignition Systems: Traditional to Modern', 'Ignition systems ignite the fuel-air mixture at the precise moment required for optimal combustion. The ignition system consists of the battery, ignition coil, spark plugs, and ignition timing control. Traditional mechanical points-based systems use mechanical contact points and a cam to open and close the ignition circuit. These systems are simple but require frequent maintenance and don''t maintain precision at high RPMs. The contact points create electrical arcing that requires careful gap adjustment and periodic replacement. Electronic ignition systems use transistors or microprocessors to control spark timing, eliminating mechanical contacts and enabling precise timing control across the entire RPM range. Electronic ignition systems automatically adjust spark timing based on engine load and RPM for optimal combustion across all conditions. Modern motorcycles integrate ignition control into the ECU (Engine Control Unit), which manages fuel injection, ignition timing, traction control, and other functions based on dozens of sensors. The ignition coil transforms 12V battery voltage into thousands of volts required to jump the spark plug gap. Modern coils use capacitive discharge (CDI) technology that stores energy in a capacitor and releases it through the coil, producing a strong spark independent of engine RPM. This enables reliable cold starting and high-RPM performance. Spark plugs gap (distance between electrodes) determines the voltage required to jump the gap—wider gaps require more voltage but can initiate combustion more reliably. Most motorcycles use either hot or cold spark plugs—hot plugs operate at higher temperatures, useful for engines running cooler or at lower speeds, while cold plugs run cooler and work better in high-RPM, high-temperature environments.', 'intermediate', 'electrical', '{"sections":[{"heading":"Traditional Points Ignition","body":"Ignition systems ignite the fuel-air mixture at the precise moment required for optimal combustion. Traditional mechanical points-based systems use mechanical contact points and a cam to open and close the ignition circuit. These systems are simple but require frequent maintenance and don''''t maintain precision at high RPMs."},{"heading":"Electronic Ignition Systems","body":"Electronic ignition systems use transistors or microprocessors to control spark timing, eliminating mechanical contacts and enabling precise timing control across the entire RPM range. Electronic ignition systems automatically adjust spark timing based on engine load and RPM for optimal combustion across all conditions."},{"heading":"Modern ECU Integration","body":"Modern motorcycles integrate ignition control into the ECU (Engine Control Unit), which manages fuel injection, ignition timing, traction control, and other functions based on dozens of sensors. This integration enables sophisticated control impossible with mechanical or basic electronic systems."},{"heading":"Spark Plug Selection","body":"Most motorcycles use either hot or cold spark plugs—hot plugs operate at higher temperatures, useful for engines running cooler or at lower speeds, while cold plugs run cooler and work better in high-RPM, high-temperature environments. Selecting the correct heat range ensures reliable operation in your conditions."}],"keyTakeaways":["Ignition systems ignite fuel at precise times for optimal combustion","Electronic systems replace mechanical points for better control","Modern ECUs integrate ignition, fuel, and other functions","Hot vs cold spark plugs depend on engine operating conditions"],"relatedTopics":["electrical","electrical-basics","spark-plug-replacement","ECU-basics"]}', 'Understand ignition system evolution from mechanical to modern ECU-controlled systems and spark plug selection.', 9, ARRAY['electrical','electrical-basics','ignition','spark','timing','ECU','fuel-injection'], true, true, true),

(gen_random_uuid(), 'spark-plug-selection-and-replacement', 'Spark Plugs: Selection and Replacement', 'Spark plugs create the spark that ignites the fuel-air mixture, and selecting the correct spark plug is essential for reliable starting and optimal engine performance. Spark plugs are identified by heat range (cold vs hot), gap (electrode distance), and material composition. Heat range describes how much heat the spark plug dissipates—hot plugs retain heat and are used in cool-running engines or low-load conditions, while cold plugs dissipate more heat and are used in high-performance or high-temperature engines. Using a heat range too hot causes pre-ignition (combustion before the spark plug fires) and damage, while using too cold a plug causes fouling (carbon buildup on the plug, disrupting spark). Spark plug gap—the distance between the center electrode and ground electrode—is critical and precisely specified by manufacturers. Wider gaps require more voltage to jump but can initiate stronger combustion, while narrower gaps are easier to fire but may not produce strong ignition. Most motorcycles use 0.7-1.0mm gaps. Many riders believe wider gaps (0.9-1.2mm) increase performance, but using gaps wider than specified can cause misfire in some conditions. Spark plug material composition varies—standard copper, platinum, iridium, and exotic materials offer different wear characteristics and prices. Copper plugs are inexpensive and good for most motorcycles, wearing out around 10,000 miles. Platinum plugs last longer (15,000+ miles) but cost more. Iridium plugs offer extreme longevity (25,000+ miles) at premium prices. Spark plug replacement is a basic maintenance task riders can perform themselves with basic tools. Check your motorcycle''s owner manual for specific heat range, gap, and replacement interval requirements.', 'beginner', 'electrical', '{"sections":[{"heading":"Spark Plug Heat Range","body":"Spark plugs are identified by heat range (cold vs hot), gap (electrode distance), and material composition. Heat range describes how much heat the spark plug dissipates—hot plugs retain heat and are used in cool-running engines or low-load conditions, while cold plugs dissipate more heat and are used in high-performance or high-temperature engines."},{"heading":"Gap Specification","body":"Spark plug gap—the distance between the center electrode and ground electrode—is critical and precisely specified by manufacturers. Wider gaps require more voltage to jump but can initiate stronger combustion, while narrower gaps are easier to fire but may not produce strong ignition. Most motorcycles use 0.7-1.0mm gaps."},{"heading":"Material Composition","body":"Spark plug material composition varies—standard copper, platinum, iridium, and exotic materials offer different wear characteristics and prices. Copper plugs are inexpensive and good for most motorcycles, wearing out around 10,000 miles. Platinum plugs last longer (15,000+ miles) but cost more. Iridium plugs offer extreme longevity (25,000+ miles) at premium prices."},{"heading":"Replacement Procedure","body":"Spark plug replacement is a basic maintenance task riders can perform themselves with basic tools. Check your motorcycle''''s owner manual for specific heat range, gap, and replacement interval requirements. Regular replacement prevents misfires, rough running, and starting difficulty."}],"keyTakeaways":["Heat range must match engine operating conditions","Gap specification is precise—check manual","Copper plugs last ~10k miles; platinum ~15k; iridium ~25k","Always follow manufacturer specifications for heat range and gap"],"relatedTopics":["electrical","ignition-systems-explained","engine-troubleshooting","maintenance"]}', 'Learn spark plug heat range, gap specification, and material choices to ensure reliable ignition and optimal performance.', 7, ARRAY['electrical','electrical-basics','spark-plug','maintenance','replacement','gap','ignition'], true, true, false),

(gen_random_uuid(), 'wiring-harness-basics', 'Motorcycle Wiring Harness Fundamentals', 'The wiring harness is the nervous system of a motorcycle, connecting the battery, starter, alternator, ignition system, lights, instruments, and controls. Understanding basic wiring helps diagnose electrical problems and makes repairs possible. Wiring colors are standardized internationally—red is positive/battery, black is negative/ground, green is neutral switch, yellow is starter, and orange is ignition system. These color standards help electricians quickly identify wires. The main battery cable runs from the positive terminal to the main fuse block and starter solenoid, carrying the massive current required for starting. Ground wires complete circuits by connecting components back to the negative battery terminal. Proper grounding is essential—a corroded or loose ground connection creates high resistance and prevents proper circuit function. Many electrical problems are actually ground issues. Connectors throughout the harness allow components to be removed for service. Motorcycle connectors use various designs—bullet connectors for simple connections, multi-pin Molex connectors for complex components, and weatherproof connectors in exposed areas. Corroded connectors create intermittent problems and poor connections—cleaning connectors often fixes mysterious electrical issues. Fusible links and fuses protect circuits from overcurrent that would damage wiring or components. Each circuit should have a properly-rated fuse; using higher-rated fuses than specified risks fire. The fuse block contains the fuses and relays controlling circuits. Identifying which fuse controls which circuit requires consulting your owner''s manual. Wiring diagram study helps riders understand circuit paths and troubleshoot problems systematically.', 'intermediate', 'electrical', '{"sections":[{"heading":"Wiring Basics and Color Standards","body":"The wiring harness is the nervous system of a motorcycle, connecting the battery, starter, alternator, ignition system, lights, instruments, and controls. Wiring colors are standardized internationally—red is positive/battery, black is negative/ground, green is neutral switch, yellow is starter, and orange is ignition system. These color standards help electricians quickly identify wires."},{"heading":"Power Distribution and Grounding","body":"The main battery cable runs from the positive terminal to the main fuse block and starter solenoid, carrying the massive current required for starting. Ground wires complete circuits by connecting components back to the negative battery terminal. Proper grounding is essential—a corroded or loose ground connection creates high resistance and prevents proper circuit function."},{"heading":"Connectors and Corrosion","body":"Connectors throughout the harness allow components to be removed for service. Motorcycle connectors use various designs—bullet connectors for simple connections, multi-pin Molex connectors for complex components, and weatherproof connectors in exposed areas. Corroded connectors create intermittent problems and poor connections—cleaning connectors often fixes mysterious electrical issues."},{"heading":"Fuses and Circuit Protection","body":"Fusible links and fuses protect circuits from overcurrent that would damage wiring or components. Each circuit should have a properly-rated fuse; using higher-rated fuses than specified risks fire. The fuse block contains the fuses and relays controlling circuits."}],"keyTakeaways":["Wiring color codes: red=positive, black=ground, green=neutral","Main battery cable carries massive starting current","Corroded ground connections cause many electrical problems","Properly-rated fuses protect circuits from overcurrent"],"relatedTopics":["electrical","electrical-troubleshooting","motorcycle-battery-types","charging-systems-explained"]}', 'Understand wiring color codes, proper grounding, connectors, and fuse protection to troubleshoot electrical issues.', 8, ARRAY['electrical','electrical-basics','wiring','connections','grounding','fuses','harness'], true, true, true),

(gen_random_uuid(), 'lighting-systems-halogen-vs-led', 'Lighting Systems: Halogen vs LED', 'Motorcycle lighting has evolved from incandescent bulbs to halogen to modern LED systems, each offering different advantages. Incandescent bulbs are simple and inexpensive but produce tremendous heat, inefficient light output, and short lifespan (500-1,000 hours). Halogen bulbs improve upon incandescent by adding halogen gas inside the bulb, increasing light output and extending lifespan to 1,000-2,000 hours. Halogen bulbs produce adequate light for street use but remain very hot, requiring careful handling—skin oils on a halogen bulb filament cause localized overheating and premature failure. LED (light-emitting diode) lights are highly efficient, producing the same light output with a fraction of the power consumption. LEDs generate minimal heat, last 20,000+ hours (often the life of the motorcycle), and are extremely durable. LED lights have transformed motorcycle lighting, enabling smaller headlights, brake lights visible for miles in daylight, and creative lighting designs. All modern motorcycles transition to LED lighting due to superior efficiency and reliability. Converting older motorcycles from halogen to LED requires caution—LEDs draw less current, potentially confusing motorcycle charging and electrical systems designed for halogen loads. Many motorcycles require resistor modules or software updates to properly control LED lights. LED color and quality varies dramatically—cheap LED units produce poor light and flicker, while quality units provide excellent illumination. Selecting appropriate lighting upgrades ensures both function and reliability. Many riders upgrade to LED lights for improved visibility and longevity.', 'intermediate', 'electrical', '{"sections":[{"heading":"Incandescent and Halogen Lighting","body":"Motorcycle lighting has evolved from incandescent bulbs to halogen to modern LED systems, each offering different advantages. Incandescent bulbs are simple and inexpensive but produce tremendous heat, inefficient light output, and short lifespan (500-1,000 hours). Halogen bulbs improve upon incandescent by adding halogen gas inside the bulb, increasing light output and extending lifespan."},{"heading":"LED Technology Advantages","body":"LED (light-emitting diode) lights are highly efficient, producing the same light output with a fraction of the power consumption. LEDs generate minimal heat, last 20,000+ hours (often the life of the motorcycle), and are extremely durable. LED lights have transformed motorcycle lighting, enabling smaller headlights and brake lights visible for miles."},{"heading":"Practical LED Installation","body":"All modern motorcycles transition to LED lighting due to superior efficiency and reliability. Converting older motorcycles from halogen to LED requires caution—LEDs draw less current, potentially confusing motorcycle charging and electrical systems designed for halogen loads. Many motorcycles require resistor modules or software updates."},{"heading":"Light Quality Considerations","body":"LED color and quality varies dramatically—cheap LED units produce poor light and flicker, while quality units provide excellent illumination. Selecting appropriate lighting upgrades ensures both function and reliability. Many riders upgrade to LED lights for improved visibility and longevity."}],"keyTakeaways":["Halogen bulbs offer better light than incandescent but require care","LEDs are extremely efficient and last 20,000+ hours","LED conversion may require resistor modules to prevent errors","Quality LED lights provide superior illumination and reliability"],"relatedTopics":["electrical","electrical-basics","lighting","battery-drain","charging-systems-explained"]}', 'Understand lighting evolution from halogen to LED and considerations for upgrading older motorcycles to LED systems.', 8, ARRAY['electrical','electrical-basics','LED','lighting','headlight','brightness','upgrade'], true, true, false),

(gen_random_uuid(), 'fuse-and-relay-systems', 'Fuse and Relay Systems Explained', 'Fuses and relays are protective and control devices that enable safe, reliable electrical system function. A fuse is a safety device that melts and breaks a circuit if current exceeds a safe level, preventing fire or component damage. Each motorcycle circuit requires a properly-rated fuse—the fuse rating must match the circuit''s designed maximum current. Using a higher-rated fuse than specified bypasses the protection and risks fire. For example, a tail light circuit rated at 5 amps should use a 5-amp fuse, never a 10-amp fuse. Fuses are cheap—replacing them is always appropriate if a fuse pops repeatedly. A fuse that pops repeatedly indicates a fault in that circuit (short circuit, overloaded component) requiring diagnosis and repair. A relay is an electromagnetic switch that uses a small current to switch a large current on and off, enabling efficient operation. The starter relay, for example, uses a small current from the ignition switch to control a large current flowing to the starter motor. Without the relay, the ignition switch would need to handle the massive starter current, making it large and dangerous. Relays have a coil (electromagnet) and contacts—when current flows through the coil, it energizes the electromagnet, closing the contacts and allowing current flow through the load. Many fuse boxes contain both fuses and relays integrated together. Understanding your motorcycle''s fuse box layout—which fuse controls which circuit—requires consulting the owner''s manual or the diagram printed on the fuse box cover. Knowing fuse locations helps riders quickly address electrical problems.', 'beginner', 'electrical', '{"sections":[{"heading":"Fuse Function and Rating","body":"A fuse is a safety device that melts and breaks a circuit if current exceeds a safe level, preventing fire or component damage. Each motorcycle circuit requires a properly-rated fuse—the fuse rating must match the circuit''''s designed maximum current. Using a higher-rated fuse than specified bypasses the protection and risks fire."},{"heading":"Identifying Fuse Problems","body":"Fuses are cheap—replacing them is always appropriate if a fuse pops repeatedly. A fuse that pops repeatedly indicates a fault in that circuit (short circuit, overloaded component) requiring diagnosis and repair. A single pop is normal; repeated pops indicate a problem."},{"heading":"Relay Operation","body":"A relay is an electromagnetic switch that uses a small current to switch a large current on and off, enabling efficient operation. The starter relay, for example, uses a small current from the ignition switch to control a large current flowing to the starter motor. Without the relay, the ignition switch would need to handle the massive starter current."},{"heading":"Fuse Box Organization","body":"Many fuse boxes contain both fuses and relays integrated together. Understanding your motorcycle''''s fuse box layout—which fuse controls which circuit—requires consulting the owner''''s manual or the diagram printed on the fuse box cover. Knowing fuse locations helps riders quickly address electrical problems."}],"keyTakeaways":["Fuses melt to break circuits if current exceeds rating","Never use higher-rated fuses than specified","Repeated fuse pops indicate a circuit fault requiring diagnosis","Relays use small current to switch large currents efficiently"],"relatedTopics":["electrical","electrical-basics","wiring-harness-basics","electrical-troubleshooting"]}', 'Learn how fuses protect circuits and relays efficiently control large currents, and understand your fuse box layout.', 7, ARRAY['electrical','electrical-basics','fuse','relay','protection','circuit','safety'], true, true, true),

(gen_random_uuid(), 'ECU-basics-engine-control', 'ECU Basics: Engine Control Units', 'Modern motorcycles use Engine Control Units (ECUs)—specialized computers that manage engine operation based on sensor inputs. The ECU reads inputs from dozens of sensors including throttle position, intake air temperature, engine temperature, manifold pressure, oxygen sensors, and many others. Based on these inputs, the ECU calculates optimal fuel injection quantity and ignition timing for the current operating conditions, then sends electrical commands to fuel injectors and ignition coils. This electronic management enables precise control impossible with mechanical or basic electronic systems, improving fuel economy, emission control, power output, and cold-start performance. Modern ECUs also manage traction control, engine braking, launch control, and other advanced functions. ECU problems often manifest as warning lights on the dashboard. A "Check Engine" light indicates the ECU has detected a fault—either a sensor problem, an out-of-range reading, or a component failure. These faults are recorded as Diagnostic Trouble Codes (DTCs) that can be read with a diagnostic scan tool. Reading the codes helps identify the fault location. Many riders simply ignore check engine lights, but faults can worsen, reducing performance and potentially causing expensive damage. Professional diagnostic service is often necessary because it requires specialized tools. ECU programming is extremely sophisticated, and ECU modification requires careful engineering—poorly done ECU tuning can damage the engine through improper fuel injection or ignition timing. Most riders should never attempt ECU tuning. Understanding that an ECU controls your motorcycle helps explain why electrical problems sometimes have complex solutions.', 'intermediate', 'electrical', '{"sections":[{"heading":"ECU Function and Sensor Inputs","body":"Modern motorcycles use Engine Control Units (ECUs)—specialized computers that manage engine operation based on sensor inputs. The ECU reads inputs from dozens of sensors including throttle position, intake air temperature, engine temperature, manifold pressure, oxygen sensors, and many others."},{"heading":"Control Outputs and Management","body":"Based on these inputs, the ECU calculates optimal fuel injection quantity and ignition timing for the current operating conditions, then sends electrical commands to fuel injectors and ignition coils. This electronic management enables precise control impossible with mechanical or basic electronic systems, improving fuel economy, emission control, power output, and cold-start performance."},{"heading":"Advanced Functions","body":"Modern ECUs also manage traction control, engine braking, launch control, and other advanced functions. These systems work together to provide safe, efficient, performance-oriented engine operation across all conditions."},{"heading":"Fault Codes and Diagnostics","body":"ECU problems often manifest as warning lights on the dashboard. A ''''Check Engine'''' light indicates the ECU has detected a fault—either a sensor problem, an out-of-range reading, or a component failure. These faults are recorded as Diagnostic Trouble Codes (DTCs) that can be read with a diagnostic scan tool."}],"keyTakeaways":["ECUs manage fuel injection, ignition, and advanced functions","They read dozens of sensors for precise control","Check Engine lights indicate faults recorded as Diagnostic Trouble Codes","ECU tuning requires professional expertise and tools"],"relatedTopics":["electrical","fuel-injection","ignition-systems-explained","electrical-troubleshooting"]}', 'Understand how Engine Control Units manage modern motorcycles and how to respond to fault codes.', 9, ARRAY['electrical','electrical-basics','ECU','computer','fuel-injection','engine-management','sensors'], true, true, false),

(gen_random_uuid(), 'electrical-troubleshooting-guide', 'Electrical Troubleshooting Guide', 'Systematic electrical troubleshooting saves time and prevents replacing expensive components unnecessarily. No-start problems begin with checking battery voltage—a healthy battery shows 12.6V or higher with the key off. Below 12.4V indicates a weak or dead battery needing charge. Below 10V indicates severe discharge or internal battery failure. With the key on but engine off, voltage should remain constant. If voltage drops when the starter button is pressed but the engine doesn''t crank, suspect either weak battery (requiring charge) or poor cable connections (requiring cleaning and securing). If the engine cranks but doesn''t start, verify spark (remove spark plug and see if it sparks when cranked) and fuel flow (turn ignition on and listen for fuel pump). No spark indicates ignition problems; no fuel indicates fuel pump or fuel delivery problems. Charging problems are verified by checking voltage at 2,000+ RPM with the engine running—a properly charging system should show 13.5-14.5V. Below 13V indicates undercharging; above 15V indicates overcharging. Undercharging suggests alternator or regulator failure; overcharging suggests regulator failure. Intermittent electrical problems are frustrating because they don''t occur consistently. These often result from corroded connections, loose ground wires, or poor-quality connectors creating intermittent contact. Finding and cleaning corroded connections often solves these problems. Carrying a multimeter and basic electrical knowledge helps riders diagnose problems roadside and decide whether professional service is necessary. Never ignore electrical problems because they often worsen and create safety issues.', 'intermediate', 'electrical', '{"sections":[{"heading":"No-Start Diagnosis","body":"Systematic electrical troubleshooting saves time and prevents replacing expensive components unnecessarily. No-start problems begin with checking battery voltage—a healthy battery shows 12.6V or higher with the key off. Below 12.4V indicates a weak or dead battery needing charge."},{"heading":"Spark and Fuel Verification","body":"With the key on but engine off, voltage should remain constant. If voltage drops when the starter button is pressed but the engine doesn''''t crank, suspect either weak battery (requiring charge) or poor cable connections (requiring cleaning and securing). If the engine cranks but doesn''''t start, verify spark and fuel flow."},{"heading":"Charging System Diagnosis","body":"Charging problems are verified by checking voltage at 2,000+ RPM with the engine running—a properly charging system should show 13.5-14.5V. Below 13V indicates undercharging; above 15V indicates overcharging. Undercharging suggests alternator or regulator failure; overcharging suggests regulator failure."},{"heading":"Intermittent Problems","body":"Intermittent electrical problems are frustrating because they don''''t occur consistently. These often result from corroded connections, loose ground wires, or poor-quality connectors creating intermittent contact. Finding and cleaning corroded connections often solves these problems."}],"keyTakeaways":["Start with battery voltage: 12.6V+ is healthy; below 12.4V needs charging","Poor connections cause many electrical problems; cleaning helps","Check charging at 2,000+ RPM: should be 13.5-14.5V","Intermittent problems often result from corroded connectors"],"relatedTopics":["electrical","motorcycle-battery-types","charging-systems-explained","wiring-harness-basics"]}', 'Learn systematic electrical troubleshooting to diagnose charging, starting, and lighting problems effectively.', 10, ARRAY['electrical','electrical-basics','troubleshooting','diagnosis','battery','charging','maintenance'], true, true, false);

-- Maintenance Articles (11 total - spread across brakes, drivetrain, tires, fuel, general)
INSERT INTO articles (id, slug, title, raw_text, difficulty, category, content_json, summary, read_time_minutes, keywords, is_seed_content, is_verified, is_safety_critical) VALUES
(gen_random_uuid(), 'brake-pad-replacement', 'Brake Pad Replacement Procedure', 'Brake pad replacement is one of the most accessible maintenance tasks riders can perform, requiring only basic tools and mechanical aptitude. Brake pads wear gradually through use—friction converts kinetic energy to heat as the pad material wears down. Worn pads reduce braking power and increase stopping distances, creating safety hazards. Most motorcycles require brake pad replacement every 15,000-30,000 miles depending on riding style and brake usage intensity. Checking pad thickness regularly prevents panic replacement during a ride. Most motorcycles have a wear indicator—either a visual inspection hole or an audible wear tab that clicks when pads are thin. To replace brake pads, remove the wheel and caliper, then slide the old pads out. Clean the caliper and rotor of brake dust and contaminants, then install new pads. Applying a small amount of anti-seize compound to the pad backing plate reduces noise and improves durability. Before re-installing the wheel, pump the brake lever to push the caliper pistons back and firmly seat the new pads. After replacement, new brake pads require a bedding-in process where braking is applied progressively to heat the pads and establish full friction contact with the rotor. During the first 100-200 miles, avoid hard braking to allow the pad material to conform to the rotor surface. Brake pad selection matters—organic pads are quieter and less damaging to rotors but wear faster. Sintered metallic pads last longer and handle heat better but are noisier and more aggressive on rotors. Most street riders use organic or semi-metallic pads appropriate for their riding style.', 'beginner', 'brakes', '{"sections":[{"heading":"Brake Pad Wear Monitoring","body":"Brake pad replacement is one of the most accessible maintenance tasks riders can perform. Brake pads wear gradually through use—friction converts kinetic energy to heat as the pad material wears down. Worn pads reduce braking power and increase stopping distances, creating safety hazards. Most motorcycles require brake pad replacement every 15,000-30,000 miles depending on riding style and brake usage intensity."},{"heading":"Replacement Process","body":"To replace brake pads, remove the wheel and caliper, then slide the old pads out. Clean the caliper and rotor of brake dust and contaminants, then install new pads. Applying a small amount of anti-seize compound to the pad backing plate reduces noise and improves durability. Before re-installing the wheel, pump the brake lever to push the caliper pistons back and firmly seat the new pads."},{"heading":"Bedding-In Procedure","body":"After replacement, new brake pads require a bedding-in process where braking is applied progressively to heat the pads and establish full friction contact with the rotor. During the first 100-200 miles, avoid hard braking to allow the pad material to conform to the rotor surface. This improves longevity and performance."},{"heading":"Pad Material Selection","body":"Brake pad selection matters—organic pads are quieter and less damaging to rotors but wear faster. Sintered metallic pads last longer and handle heat better but are noisier and more aggressive on rotors. Most street riders use organic or semi-metallic pads appropriate for their riding style."}],"keyTakeaways":["Check pad thickness regularly and replace at 15,000-30,000 miles","Organic pads are quiet; sintered metallic pads last longer","New pads require bedding-in over 100-200 miles","Anti-seize compound reduces pad noise and improves durability"],"relatedTopics":["maintenance","brake-system-safety","chain-maintenance","tire-inspection"]}', 'Learn to replace brake pads safely and correctly, including bedding-in procedure for optimal performance and longevity.', 9, ARRAY['maintenance','brakes','brake-pads','service','replacement','safety-critical','brake-service'], true, true, true),

(gen_random_uuid(), 'brake-system-safety', 'Brake System Safety and Inspection', 'Brakes are the most critical safety system on a motorcycle—brake failure can cause catastrophic accidents. A proper brake inspection should be performed every month or before long rides. Check brake fluid level through the sight glass on the master cylinder—it should be between the minimum and maximum marks. Low brake fluid indicates a leak or worn brake pads pushing the pistons further into the calipers. A leak requires immediate professional service; worn pads require replacement. Check brake fluid condition—it should be clear to slightly amber. Discolored, black, or milky fluid indicates water contamination and requires a brake fluid flush. Brake fluid absorbs moisture over time, degrading its performance and lowering its boiling point. Flushed brake fluid should be completely replaced according to the manufacturer''s interval (typically 2 years). Squeeze the brake lever—it should feel firm and never reach the handlebar. A soft, spongy lever indicates air in the brake lines, requiring bleeding to remove the air. Brake lever position should remain consistent and return to rest position when released. Check brake rotor condition by visual inspection—rotors should be smooth and free of deep cracks, pitting, or warping. Rotors with scoring marks or visible wear grooves approaching the wear limit need replacement. Spin the wheel and listen for rotor dragging against the pads—a dragging sound indicates caliper misalignment or stuck pistons. Most brake problems are prevented through routine inspection and maintenance. Never ignore spongy brakes or unusual noises because brakes are critical for your safety.', 'intermediate', 'brakes', '{"sections":[{"heading":"Brake Fluid Inspection","body":"Brakes are the most critical safety system on a motorcycle—brake failure can cause catastrophic accidents. Check brake fluid level through the sight glass on the master cylinder—it should be between the minimum and maximum marks. Low brake fluid indicates a leak or worn brake pads pushing the pistons further into the calipers."},{"heading":"Brake Fluid Condition and Flushing","body":"Check brake fluid condition—it should be clear to slightly amber. Discolored, black, or milky fluid indicates water contamination and requires a brake fluid flush. Brake fluid absorbs moisture over time, degrading its performance and lowering its boiling point. Flushed brake fluid should be completely replaced according to the manufacturer''''s interval (typically 2 years)."},{"heading":"Brake Lever and Pressure Check","body":"Squeeze the brake lever—it should feel firm and never reach the handlebar. A soft, spongy lever indicates air in the brake lines, requiring bleeding to remove the air. Brake lever position should remain consistent and return to rest position when released."},{"heading":"Rotor and Caliper Inspection","body":"Check brake rotor condition by visual inspection—rotors should be smooth and free of deep cracks, pitting, or warping. Rotors with scoring marks or visible wear grooves approaching the wear limit need replacement. Spin the wheel and listen for rotor dragging against the pads—a dragging sound indicates caliper misalignment or stuck pistons."}],"keyTakeaways":["Check brake fluid level monthly and replace if low","Discolored fluid indicates water contamination requiring flush","Spongy brake lever indicates air in lines needing bleeding","Damaged rotors or dragging indicate caliper problems"],"relatedTopics":["maintenance","brake-pad-replacement","tire-inspection","pre-ride-checklist"]}', 'Perform comprehensive brake system inspections to ensure your most critical safety system functions reliably.', 10, ARRAY['maintenance','brakes','safety-critical','inspection','brake-fluid','rotor','caliper'], true, true, true),

(gen_random_uuid(), 'chain-maintenance-guide', 'Chain Maintenance: Cleaning and Lubrication', 'The motorcycle chain is a precision mechanical component requiring regular care to ensure smooth power delivery and long lifespan. A dry, neglected chain becomes stiff and causes power loss, excessive noise, and accelerated wear that can eventually break during riding. Regular cleaning removes dirt, sand, and debris that accelerates chain wear. Use a plastic chain brush and warm soapy water to clean the chain thoroughly, removing buildup from both sides and the rollers. After cleaning, dry the chain completely with a compressed air or cloth. Apply chain lubricant designed for motorcycles—car lubricants lack the necessary adhesive properties and wash off too quickly. Spray lubricant evenly along the inside of the chain where the pins and rollers are located. Allow 10 minutes for the lubricant to penetrate before riding. Most motorcycles require chain cleaning and lubrication every 500-800 miles, though this depends on riding conditions and environmental exposure. Dirty or muddy riding increases frequency significantly. A properly maintained chain can last 15,000-20,000 miles; neglected chains wear out in 5,000 miles or less. Check chain tension monthly—the chain should have about 25-35mm of vertical movement at its midpoint. Excessive looseness allows the chain to skip teeth and jump sprockets; excessive tightness increases wear and reduces engine power. Proper tension is critical for safety and longevity. If the chain develops tight spots (sections that require more effort to rotate), it''s beginning to fail and needs replacement. A snapped chain during riding causes sudden engine braking that can destabilize the motorcycle.', 'beginner', 'drivetrain', '{"sections":[{"heading":"Importance of Chain Maintenance","body":"The motorcycle chain is a precision mechanical component requiring regular care to ensure smooth power delivery and long lifespan. A dry, neglected chain becomes stiff and causes power loss, excessive noise, and accelerated wear that can eventually break during riding."},{"heading":"Cleaning Procedure","body":"Regular cleaning removes dirt, sand, and debris that accelerates chain wear. Use a plastic chain brush and warm soapy water to clean the chain thoroughly, removing buildup from both sides and the rollers. After cleaning, dry the chain completely with compressed air or cloth."},{"heading":"Lubrication and Maintenance Interval","body":"Apply chain lubricant designed for motorcycles—car lubricants lack the necessary adhesive properties and wash off too quickly. Spray lubricant evenly along the inside of the chain where the pins and rollers are located. Most motorcycles require chain cleaning and lubrication every 500-800 miles."},{"heading":"Tension and Wear Monitoring","body":"Check chain tension monthly—the chain should have about 25-35mm of vertical movement at its midpoint. Excessive looseness allows the chain to skip teeth and jump sprockets; excessive tightness increases wear and reduces engine power. A properly maintained chain can last 15,000-20,000 miles; neglected chains wear out in 5,000 miles or less."}],"keyTakeaways":["Clean chain every 500-800 miles with brush and soapy water","Lubricate with motorcycle-specific chain lubricant after cleaning","Maintain chain tension at 25-35mm vertical movement midpoint","Properly maintained chains last 15,000-20,000 miles"],"relatedTopics":["maintenance","tire-inspection","oil-change-procedure","pre-ride-checklist"]}', 'Learn proper chain cleaning, lubrication, and tension procedures to maximize chain life and ensure safe power delivery.', 8, ARRAY['maintenance','drivetrain','chain','lubrication','cleaning','service','motorcycle-maintenance'], true, true, false),

(gen_random_uuid(), 'tire-inspection-and-care', 'Tire Inspection and Maintenance', 'Motorcycle tires are your only contact with the road and critically affect safety, handling, and performance. Regular tire inspection prevents dangerous situations and expensive blowouts. Check tire pressure monthly with a quality gauge—correct pressure is printed on the bike''s label, usually 32-36 PSI front and rear for street bikes. Underinflated tires cause excess flex, generating heat and reducing grip; overinflated tires reduce contact area and create a harsh ride. Pressure changes with temperature—tires lose about 1 PSI per 10°C temperature drop. Check pressure when tires are cold (before riding) for accurate measurement. Check tread depth by inserting a penny into the tread grooves—if you can see the top of Lincoln''s head, the tread is too shallow and needs replacement. Most motorcycles need tire replacement at 5-10mm remaining tread depth for safety. Worn tires offer less grip and hydroplane on wet roads at lower speeds. Inspect sidewalls for cracks, bulges, or damage indicating internal structural compromise. Sidewall damage requires immediate tire replacement. Look for embedded objects like nails or glass—if an object is embedded in the tread, the tire usually cannot be safely repaired. Check tire age—tires older than 10 years should be replaced regardless of tread depth due to rubber degradation. Tires should be balanced and aligned properly. Unbalanced tires cause vibration and uneven wear; misalignment accelerates tire wear and compromises handling. Many tire problems are prevented through proper pressure maintenance and regular inspection.', 'beginner', 'tires', '{"sections":[{"heading":"Tire Pressure Management","body":"Motorcycle tires are your only contact with the road and critically affect safety, handling, and performance. Check tire pressure monthly with a quality gauge—correct pressure is printed on the bike''''s label, usually 32-36 PSI front and rear for street bikes. Underinflated tires cause excess flex, generating heat and reducing grip; overinflated tires reduce contact area and create a harsh ride."},{"heading":"Tread Depth Assessment","body":"Check tread depth by inserting a penny into the tread grooves—if you can see the top of Lincoln''''s head, the tread is too shallow and needs replacement. Most motorcycles need tire replacement at 5-10mm remaining tread depth for safety. Worn tires offer less grip and hydroplane on wet roads at lower speeds."},{"heading":"Sidewall and Structural Inspection","body":"Inspect sidewalls for cracks, bulges, or damage indicating internal structural compromise. Sidewall damage requires immediate tire replacement. Look for embedded objects like nails or glass—if an object is embedded in the tread, the tire usually cannot be safely repaired."},{"heading":"Age and Balance Considerations","body":"Check tire age—tires older than 10 years should be replaced regardless of tread depth due to rubber degradation. Tires should be balanced and aligned properly. Unbalanced tires cause vibration and uneven wear; misalignment accelerates tire wear and compromises handling."}],"keyTakeaways":["Check tire pressure monthly; correct pressure printed on bike label","Penny test: if you see Lincoln''''s head, tread is too shallow","Replace tires at 5-10mm remaining tread depth for safety","Replace tires older than 10 years regardless of tread depth"],"relatedTopics":["maintenance","tire-safety","chain-maintenance-guide","pre-ride-checklist"]}', 'Master tire inspection, pressure maintenance, and tread depth assessment to ensure grip, safety, and handling.', 8, ARRAY['maintenance','tires','safety-critical','pressure','tread','inspection','service'], true, true, true),

(gen_random_uuid(), 'fuel-system-maintenance', 'Fuel System Maintenance and Care', 'Fuel system problems often manifest as poor starting, hesitation, or loss of power. Proper maintenance prevents these issues. Fuel degrades over time—gasoline contains volatile compounds that oxidize and form varnish deposits. Stale fuel left in the tank over months can form gum deposits that clog injectors and carburetors. Store motorcycles with a full fuel tank (leaving air space creates moisture) or use a fuel stabilizer if storing longer than two months. Stabilizers prevent oxidation and keep fuel usable for extended periods. If your motorcycle has been sitting with old fuel, drain the tank and refill with fresh fuel before diagnosing starting problems. Fuel filters trap contaminants and water before they reach injectors or carburetors. Fuel filters gradually become clogged through normal use—a severely clogged filter restricts fuel flow and reduces engine performance. Most motorcycles have fuel filters requiring replacement every 2-3 years or 15,000-20,000 miles. Access depends on motorcycle design—some have replaceable cartridge filters, others have sealed units requiring tank removal. Fuel tank vents can become clogged with debris, preventing proper tank ventilation during fuel consumption. A clogged vent creates a vacuum in the tank that eventually starves the fuel pump and stops fuel flow. If your motorcycle runs briefly then dies (fuel starvation symptom), check the fuel filler cap vent. Some motorcycles use a charcoal canister to filter fuel vapors during storage—this should be checked for clogging periodically. Regular fuel system maintenance prevents most fuel-related problems.', 'intermediate', 'fuel', '{"sections":[{"heading":"Fuel Degradation and Storage","body":"Fuel degrades over time—gasoline contains volatile compounds that oxidize and form varnish deposits. Stale fuel left in the tank over months can form gum deposits that clog injectors and carburetors. Store motorcycles with a full fuel tank (leaving air space creates moisture) or use a fuel stabilizer if storing longer than two months."},{"heading":"Fuel Filter Service","body":"Fuel filters trap contaminants and water before they reach injectors or carburetors. Fuel filters gradually become clogged through normal use—a severely clogged filter restricts fuel flow and reduces engine performance. Most motorcycles have fuel filters requiring replacement every 2-3 years or 15,000-20,000 miles."},{"heading":"Tank Vent Maintenance","body":"Fuel tank vents can become clogged with debris, preventing proper tank ventilation during fuel consumption. A clogged vent creates a vacuum in the tank that eventually starves the fuel pump and stops fuel flow. If your motorcycle runs briefly then dies (fuel starvation symptom), check the fuel filler cap vent."},{"heading":"Fuel System Diagnosis","body":"If your motorcycle has been sitting with old fuel, drain the tank and refill with fresh fuel before diagnosing starting problems. Regular fuel system maintenance prevents most fuel-related problems. Fuel system issues often manifest as poor starting, hesitation, or loss of power."}],"keyTakeaways":["Store with full tank or use fuel stabilizer to prevent degradation","Replace fuel filters every 2-3 years or 15,000-20,000 miles","Clogged fuel tank vent causes fuel starvation and stopping","Drain old fuel and refill fresh before diagnosing starting issues"],"relatedTopics":["maintenance","fuel-injection","carburetor-basics","pre-ride-checklist"]}', 'Maintain fuel system health through proper storage, filter replacement, and vent management to prevent fuel starvation.', 9, ARRAY['maintenance','fuel','fuel-system','service','storage','filter','injection'], true, true, false),

(gen_random_uuid(), 'oil-change-procedure', 'Oil Change Step-by-Step Procedure', 'Oil changes are the most fundamental motorcycle maintenance task, preventing engine wear and extending engine life dramatically. Most motorcycles require oil changes every 3,000-6,000 miles depending on riding intensity and engine design. Plan to change oil while the engine is warm—warm oil flows better and suspends particles more completely. Let the engine run at idle for a minute, then turn it off and wait 5 minutes before draining. Position the motorcycle on a stable surface or center stand. Loosen the oil drain plug (located at the bottom of the engine) and carefully remove it, allowing the old oil to drain into a container. Remove the old oil filter—use an oil filter wrench if it''s tight. Wipe the filter seat clean with a cloth and install a new filter, tightening it by hand until the rubber seal makes contact, then turning an additional three-quarter turn. Do not over-tighten filters. Check the drain plug for damage—if the threads are stripped or the plug is damaged, replace it rather than stripping threads further. Install a new crush washer if your motorcycle uses them (consult manual). Install the drain plug and tighten to manufacturer specification. Add the specified quantity and grade of oil through the filler cap. Check the oil level using the sight glass or dipstick, adding more if needed. Start the engine and check for leaks around the drain plug and filter. Turn the engine off and let it settle for 5 minutes, then check the oil level again and top up if necessary. Dispose of used oil properly at recycling centers or auto parts stores—never dump oil in the ground or drain.', 'beginner', 'general', '{"sections":[{"heading":"Oil Change Timing and Preparation","body":"Oil changes are the most fundamental motorcycle maintenance task, preventing engine wear and extending engine life dramatically. Most motorcycles require oil changes every 3,000-6,000 miles depending on riding intensity and engine design. Plan to change oil while the engine is warm—warm oil flows better and suspends particles more completely."},{"heading":"Drain and Filter Replacement","body":"Position the motorcycle on a stable surface or center stand. Loosen the oil drain plug (located at the bottom of the engine) and carefully remove it, allowing the old oil to drain into a container. Remove the old oil filter—use an oil filter wrench if it''''s tight. Wipe the filter seat clean with a cloth and install a new filter, tightening it by hand."},{"heading":"Drain Plug and Installation","body":"Check the drain plug for damage—if the threads are stripped or the plug is damaged, replace it rather than stripping threads further. Install a new crush washer if your motorcycle uses them. Install the drain plug and tighten to manufacturer specification."},{"heading":"Oil Level Check and Final Steps","body":"Add the specified quantity and grade of oil through the filler cap. Check the oil level using the sight glass or dipstick, adding more if needed. Start the engine and check for leaks around the drain plug and filter. Dispose of used oil properly at recycling centers or auto parts stores."}],"keyTakeaways":["Change oil every 3,000-6,000 miles with warm engine","Use specified oil grade—wrong viscosity damages engine","Don''''t over-tighten filter; three-quarter turn after seal contact","Check oil level again after engine warm-up and settling","Dispose of old oil at recycling centers, never dump on ground"],"relatedTopics":["maintenance","oil-system-fundamentals","engine-break-in","pre-ride-checklist"]}', 'Perform proper oil changes with correct procedure, oil grade, and disposal to maintain engine health and longevity.', 9, ARRAY['maintenance','oil','service','engine','fluid','replacement','general-maintenance'], true, true, false),

(gen_random_uuid(), 'pre-ride-safety-checklist', 'Pre-Ride Safety Checklist', 'Performing a quick pre-ride inspection prevents breakdowns and accidents. A thorough inspection takes 5-10 minutes and can identify problems before they become dangerous. Start by checking tire pressure and condition—visually inspect for damage, embedded objects, and adequate tread depth. Low tires indicate possible leaks. Check brake lever and pedal for firm feel and proper operation. Soft or low-traveling brakes indicate air in lines or worn pads. Check throttle operation—it should move freely and return to idle when released. Stuck throttles cause dangerous acceleration. Verify all lights function—headlight, taillight, brake light, and turn signals. Non-functioning lights create safety hazards at night and prevent other riders from seeing your intentions. Check mirrors for proper adjustment and cleanliness. Check the fuel level—you cannot fuel up if your tank is empty on the road. Open the fuel petcock to verify fuel flows (for carbureted bikes). Check coolant level if your motorcycle uses liquid cooling—low coolant can cause overheating during riding. Check the battery indicator light briefly to ensure charging system is functioning. Check for fluid leaks under the motorcycle—a small pool of fluid indicates a developing problem. Listen to the engine—it should start easily and idle smoothly without unusual noises. The pre-ride check is especially important before long rides or if the motorcycle has been sitting unused. Many serious accidents and breakdowns are prevented by taking five minutes for a basic inspection.', 'beginner', 'general', '{"sections":[{"heading":"Tire and Brake Inspection","body":"Performing a quick pre-ride inspection prevents breakdowns and accidents. Start by checking tire pressure and condition—visually inspect for damage, embedded objects, and adequate tread depth. Low tires indicate possible leaks. Check brake lever and pedal for firm feel and proper operation. Soft or low-traveling brakes indicate air in lines or worn pads."},{"heading":"Controls and Light Check","body":"Check throttle operation—it should move freely and return to idle when released. Stuck throttles cause dangerous acceleration. Verify all lights function—headlight, taillight, brake light, and turn signals. Non-functioning lights create safety hazards at night and prevent other riders from seeing your intentions."},{"heading":"Fuel and Cooling Systems","body":"Check the fuel level—you cannot fuel up if your tank is empty on the road. Open the fuel petcock to verify fuel flows (for carbureted bikes). Check coolant level if your motorcycle uses liquid cooling—low coolant can cause overheating during riding."},{"heading":"Final Checks","body":"Check mirrors for proper adjustment and cleanliness. Check for fluid leaks under the motorcycle—a small pool of fluid indicates a developing problem. Listen to the engine—it should start easily and idle smoothly without unusual noises. The pre-ride check is especially important before long rides."}],"keyTakeaways":["Check tires, brakes, and fuel before every ride","Verify all lights function and mirrors are clean","Listen for unusual engine noises or difficulty starting","Five-minute pre-ride check prevents breakdowns and accidents"],"relatedTopics":["maintenance","tire-inspection-and-care","brake-system-safety","general-safety"]}', 'Perform a comprehensive pre-ride inspection to catch potential problems before they cause breakdowns or accidents.', 6, ARRAY['maintenance','pre-ride','safety-critical','inspection','checklist','general-maintenance'], true, true, true),

(gen_random_uuid(), 'coolant-flush-procedure', 'Coolant Flush and System Maintenance', 'Coolant is critical for heat management and corrosion prevention in liquid-cooled engines. Over time, coolant becomes contaminated with corrosion byproducts and loses effectiveness. Flushing coolant every 2-3 years or per manufacturer specification maintains cooling system health. A complete coolant flush removes old fluid and corrosion deposits that accumulate in the system. To flush coolant, first allow the engine to cool completely to avoid burns from hot fluid. Remove the lower radiator hose at the radiator and drain old coolant into a container. Refill the system with distilled water and run the engine until it reaches operating temperature, circulating the water through the system. Turn off the engine, let it cool, and drain the water. Repeat this flushing process 2-3 times until the drained fluid runs clear. After the final flush, install a new thermostat if your motorcycle uses a replaceable one—old thermostats can stick and prevent proper circulation. Refill the system with the correct coolant type and concentration (typically 50/50 mix of coolant and distilled water). Run the engine and watch for air bubbles in the coolant overflow, which indicates air trapped in the system. Top off the coolant level when bubbles stop appearing. Never mix different coolant types as they use different additives that can react poorly. Check coolant level monthly—a declining level indicates a leak. Identify leaks and repair them before the coolant depletes completely, as running with low coolant causes overheating. Proper coolant maintenance prevents overheating, corrosion, and expensive radiator and engine damage.', 'intermediate', 'general', '{"sections":[{"heading":"Coolant Function and Degradation","body":"Coolant is critical for heat management and corrosion prevention in liquid-cooled engines. Over time, coolant becomes contaminated with corrosion byproducts and loses effectiveness. Flushing coolant every 2-3 years or per manufacturer specification maintains cooling system health."},{"heading":"Flushing Procedure","body":"To flush coolant, first allow the engine to cool completely to avoid burns from hot fluid. Remove the lower radiator hose at the radiator and drain old coolant into a container. Refill the system with distilled water and run the engine until it reaches operating temperature, circulating the water through the system."},{"heading":"Thermostat and Refilling","body":"After the final flush, install a new thermostat if your motorcycle uses a replaceable one—old thermostats can stick and prevent proper circulation. Refill the system with the correct coolant type and concentration (typically 50/50 mix of coolant and distilled water). Run the engine and watch for air bubbles in the coolant overflow."},{"heading":"Leak Detection and Maintenance","body":"Never mix different coolant types as they use different additives that can react poorly. Check coolant level monthly—a declining level indicates a leak. Identify leaks and repair them before the coolant depletes completely, as running with low coolant causes overheating."}],"keyTakeaways":["Flush coolant every 2-3 years to remove corrosion deposits","Use 50/50 mix of coolant and distilled water","Refill after flush and check for air bubbles","Check coolant level monthly for leaks","Low coolant causes overheating and engine damage"],"relatedTopics":["maintenance","engine-cooling-systems","general-maintenance","pre-ride-checklist"]}', 'Maintain your cooling system through regular coolant flushing to prevent overheating and engine damage.', 9, ARRAY['maintenance','coolant','cooling','service','general-maintenance','liquid-cooling'], true, true, false),

(gen_random_uuid(), 'winterization-guide', 'Winterization: Storing Your Motorcycle', 'Proper winterization prevents damage during off-season storage and ensures your motorcycle starts easily in spring. Before storing, perform an oil change using fresh oil, which removes acidic combustion byproducts that can damage engine components during extended shutdown. Fill the fuel tank with fresh fuel and add a fuel stabilizer, which prevents gas from oxidizing and forming varnish deposits. For extended storage (more than two months), run the engine for 10-15 minutes to distribute the stabilized fuel throughout the fuel system. Alternatively, run the engine normally until you are confident the stabilizer has circulated. Check and top off all fluids—oil, coolant, and brake fluid. Low fluid levels during storage allow water absorption and oxidation. Ensure the battery is fully charged—a dead battery sulfates and loses capacity permanently. Connect a trickle charger (also called a smart charger) that maintains the battery charge at a safe level throughout storage. Without charging, the battery will be dead in 3-4 months of storage. Wash the motorcycle thoroughly, removing all salt and grime that cause corrosion. Dry it completely. Cover exposed metal with light oil to prevent oxidation. Store the motorcycle in a dry location—moisture and humidity cause rust. Inflate tires to manufacturer specification or slightly higher to prevent flat-spotting during months of immobilization. If possible, place the motorcycle on a stand rather than resting on the tires. Cover the motorcycle with a breathable cover to prevent dust accumulation while allowing moisture to escape (non-breathable covers trap moisture and cause corrosion). Store the motorcycle in a secure, stable location away from weather and thieves.', 'intermediate', 'general', '{"sections":[{"heading":"Fluid Management and Oil Change","body":"Proper winterization prevents damage during off-season storage and ensures your motorcycle starts easily in spring. Before storing, perform an oil change using fresh oil, which removes acidic combustion byproducts that can damage engine components during extended shutdown. Fill the fuel tank with fresh fuel and add a fuel stabilizer."},{"heading":"Fuel System and Battery Care","body":"For extended storage (more than two months), run the engine for 10-15 minutes to distribute the stabilized fuel throughout the fuel system. Ensure the battery is fully charged—a dead battery sulfates and loses capacity permanently. Connect a trickle charger (also called a smart charger) that maintains the battery charge at a safe level throughout storage."},{"heading":"Cleaning and Protection","body":"Wash the motorcycle thoroughly, removing all salt and grime that cause corrosion. Dry it completely. Cover exposed metal with light oil to prevent oxidation. Store the motorcycle in a dry location—moisture and humidity cause rust."},{"heading":"Storage Preparation","body":"Inflate tires to manufacturer specification or slightly higher to prevent flat-spotting during months of immobilization. If possible, place the motorcycle on a stand rather than resting on the tires. Cover the motorcycle with a breathable cover to prevent dust accumulation while allowing moisture to escape."}],"keyTakeaways":["Change oil before storage to remove combustion byproducts","Add fuel stabilizer and run engine to circulate it","Connect trickle charger to maintain battery charge","Store in dry location with breathable cover to prevent rust"],"relatedTopics":["maintenance","oil-change-procedure","motorcycle-battery-types","general-maintenance"]}', 'Properly winterize and store your motorcycle to prevent damage and ensure easy spring starting.', 10, ARRAY['maintenance','storage','winterization','general-maintenance','preparation','battery','fuel'], true, true, false),

(gen_random_uuid(), 'air-filter-service', 'Air Filter Service and Replacement', 'Air filters prevent dirt and debris from entering the engine, protecting cylinders and internal components from abrasive wear. A clogged air filter restricts intake airflow, reducing engine power and efficiency. Most motorcycles have replaceable cartridge air filters requiring service every 10,000-20,000 miles depending on riding conditions. Riders in dusty or sandy environments need more frequent service. To service the air filter, locate the filter box (typically mounted to the airbox near the engine). Remove the filter box cover and carefully extract the filter. Tap the filter gently to dislodge loose dust, or use a shop vacuum carefully to avoid forcing dirt deeper into the pleats. Never wash the filter with water—this forces dirt into the pleats. Inspect the filter for tears or damage—a damaged filter allows unfiltered air to enter the engine, causing accelerated wear. If damaged, replace with a new filter. If the filter is in good condition, reinstall it. Never operate without a filter or with a damaged filter. When replacing with a new filter, ensure you purchase the correct part number for your specific motorcycle. Aftermarket air filters with different designs (different colored papers, synthetic materials) may alter engine performance and should be selected carefully. Some motorcycle models allow cleaning the filter with compressed air—check your owner''s manual for proper procedures. A clean air filter improves throttle response, fuel economy, and engine longevity by preventing abrasive contamination from entering cylinders.', 'beginner', 'general', '{"sections":[{"heading":"Air Filter Function and Service Interval","body":"Air filters prevent dirt and debris from entering the engine, protecting cylinders and internal components from abrasive wear. A clogged air filter restricts intake airflow, reducing engine power and efficiency. Most motorcycles have replaceable cartridge air filters requiring service every 10,000-20,000 miles depending on riding conditions."},{"heading":"Cleaning Procedure","body":"To service the air filter, locate the filter box (typically mounted to the airbox near the engine). Remove the filter box cover and carefully extract the filter. Tap the filter gently to dislodge loose dust, or use a shop vacuum carefully to avoid forcing dirt deeper into the pleats."},{"heading":"Inspection and Replacement","body":"Inspect the filter for tears or damage—a damaged filter allows unfiltered air to enter the engine, causing accelerated wear. If damaged, replace with a new filter. If the filter is in good condition, reinstall it. Never operate without a filter or with a damaged filter."},{"heading":"Filter Selection","body":"When replacing with a new filter, ensure you purchase the correct part number for your specific motorcycle. Aftermarket air filters with different designs (different colored papers, synthetic materials) may alter engine performance and should be selected carefully."}],"keyTakeaways":["Service air filter every 10,000-20,000 miles depending on conditions","Tap or vacuum filter to clean; never wash with water","Replace if damaged; never operate without filter","Use manufacturer-correct part number for replacement filter"],"relatedTopics":["maintenance","general-maintenance","fuel-system-maintenance","engine-performance"]}', 'Service your air filter regularly to maintain engine power, efficiency, and protect internal components from wear.', 7, ARRAY['maintenance','air-filter','service','general-maintenance','engine','filtration'], true, true, false);

COMMIT;



